import{_ as r,o as a,c as i,a3 as t}from"./chunks/framework.LBeL10WQ.js";const m=JSON.parse('{"title":"1. Brief Annonceur","description":"","frontmatter":{"title":"1. Brief Annonceur"},"headers":[],"relativePath":"advertisers/dedicated-email/1-brief-annonceur.md","filePath":"advertisers/dedicated-email/1-brief-annonceur.md"}'),s={name:"advertisers/dedicated-email/1-brief-annonceur.md"};function n(o,e,l,u,d,c){return a(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="etape-1-le-brief-annonceur" tabindex="-1">Étape 1 : Le Brief Annonceur <a class="header-anchor" href="#etape-1-le-brief-annonceur" aria-label="Permalink to &quot;Étape 1 : Le Brief Annonceur&quot;">​</a></h1><p>Votre rôle : fournir la &quot;matière première&quot; qui permettra au distributeur de construire un email performant.</p><hr><h2 id="remplir-le-formulaire" tabindex="-1">Remplir le formulaire <a class="header-anchor" href="#remplir-le-formulaire" aria-label="Permalink to &quot;Remplir le formulaire&quot;">​</a></h2><p>Toute campagne débute par la soumission du brief via notre formulaire dédié.</p><p>→ <strong><a href="https://tally.so/r/9qN9WY" target="_blank">Accéder au formulaire Brief (Tally)</a></strong></p><hr><h2 id="ce-que-vous-devez-fournir" tabindex="-1">Ce que vous devez fournir <a class="header-anchor" href="#ce-que-vous-devez-fournir" aria-label="Permalink to &quot;Ce que vous devez fournir&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>🎁 L&#39;Offre</strong><p>Quelle est la promesse ? Soyez clair et incitatif. Exemple : <em>&quot;20€ offerts dès 100€ d&#39;achat&quot;</em>.</p><p>Précisez la durée de validité (minimum recommandé : 3 mois).</p></div><div class="gi-value-card"><strong>🖼️ Les Visuels</strong><p>Logo en vectoriel ou HD, packshots produits sur fond blanc, visuels d&#39;ambiance si disponibles.</p></div><div class="gi-value-card"><strong>✍️ Le Wording</strong><p>Arguments clés (USP), ton de la marque, mots-clés obligatoires à intégrer dans le texte de l&#39;email.</p></div><div class="gi-value-card"><strong>🔗 Les Liens</strong><p>URLs de destination (landing pages) vers lesquelles rediriger le trafic. Ces liens sont dynamiques — modifiables à tout moment.</p></div></div><div class="tip custom-block"><p class="custom-block-title">Conseil : laissez le distributeur adapter</p><p>Ne cherchez pas à imposer une charte graphique stricte. C&#39;est le distributeur qui connaît sa communauté — laissez-le adapter vos visuels à son univers pour maximiser l&#39;engagement.</p><p><strong>L&#39;objectif est une recommandation, pas une publicité.</strong> Un email 100% à vos couleurs sans mention du partenaire augmente les désabonnements et fait chuter la performance.</p></div><hr><h2 id="et-ensuite" tabindex="-1">Et ensuite ? <a class="header-anchor" href="#et-ensuite" aria-label="Permalink to &quot;Et ensuite ?&quot;">​</a></h2><p>Une fois le brief envoyé, l&#39;équipe getinside configure la campagne et notifie le distributeur pour démarrer la création.</p><p>→ Étape suivante : <a href="./2-creation-distributeur.html">Production &amp; Co-branding</a></p>',14)])])}const f=r(s,[["render",n]]);export{m as __pageData,f as default};
